# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify, make_response
import uuid
from datetime import datetime, timedelta
import jwt

app = Flask(__name__)

# Mock database
database = {}

@app.route('/reset-password', methods=['POST'])
def reset_password():
    data = request.get_json()
    email = data.get('email')

    if not email:
        return jsonify({'error': 'Email is required'}), 400

    # Generate a random token
    token = str(uuid.uuid4())
    expiration_time = datetime.utcnow() + timedelta(hours=1)

    # Store the token and its expiration time in the database
    database[email] = {
        'token': token,
        'expires_at': expiration_time
    }

    # Send the reset link (for simplicity, just print it)
    reset_link = f"http://example.com/reset?email={email}&token={token}"
    print(reset_link)

    return jsonify({'message': 'Reset link sent'}), 200

if __name__ == '__main__':
    app.run(debug=True)